#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

const REPO_ROOT = path.resolve(__dirname, '..');
const LEVELS_DIR = path.join(REPO_ROOT, 'levels');
const LEVELS_JS_PATH = path.join(REPO_ROOT, 'js', 'levels.js');
const OUTPUT_PATH = path.join(REPO_ROOT, 'js', 'levels-bundle.js');

function readLevelFileList(){
  const source = fs.readFileSync(LEVELS_JS_PATH, 'utf8');
  const listMatch = source.match(/const\s+LEVEL_DATA_FILES\s*=\s*\[(.*?)\];/s);
  if(!listMatch){
    throw new Error('Unable to locate LEVEL_DATA_FILES in js/levels.js');
  }
  const arrayBody = listMatch[1];
  const matches = Array.from(arrayBody.matchAll(/['\"]([^'\"]+\.json)['\"]/g));
  if(!matches.length){
    throw new Error('LEVEL_DATA_FILES appears to be empty.');
  }
  return matches.map(match => match[1]);
}

function loadJson(filePath){
  const raw = fs.readFileSync(filePath, 'utf8');
  return JSON.parse(raw);
}

function indent(text, spaces){
  const pad = ' '.repeat(spaces);
  return text.split('\n').map(line => pad + line).join('\n');
}

function buildBundle(){
  const files = readLevelFileList();
  const entries = files.map(fileName => {
    const absolute = path.join(LEVELS_DIR, fileName);
    if(!fs.existsSync(absolute)){
      throw new Error(`Missing level file: ${fileName}`);
    }
    const data = loadJson(absolute);
    return { fileName, data };
  });

  const lines = [];
  lines.push('// This file is auto-generated by tools/build-level-bundle.js');
  lines.push('// Do not edit this file manually.');
  lines.push('(function(){');
  lines.push("  if(typeof window !== 'undefined'){");
  lines.push('    const bundle = window.LEVEL_DATA_BUNDLE = window.LEVEL_DATA_BUNDLE || Object.create(null);');
  lines.push('    bundle.__generatedAt = ' + JSON.stringify(new Date().toISOString()) + ';');
  for(const entry of entries){
    const json = JSON.stringify(entry.data, null, 2);
    const assignment = `bundle[${JSON.stringify(entry.fileName)}] = ${json};`;
    lines.push(indent(assignment, 4));
  }
  lines.push('  }');
  lines.push('})();');

  const content = lines.join('\n') + '\n';
  fs.writeFileSync(OUTPUT_PATH, content, 'utf8');
}

try{
  buildBundle();
  console.log(`Wrote level bundle to ${path.relative(REPO_ROOT, OUTPUT_PATH)}`);
}catch(err){
  console.error(err.message);
  process.exitCode = 1;
}
